import jwt
from datetime import datetime, timedelta

# Secret Key (يجب أن يكون قوي وسري)
SECRET_KEY = "your-super-secret-key"

# ----------------------------------
# Login: إنشاء JWT بعد تسجيل الدخول
# ----------------------------------
def login(username, password):

    # البحث عن المستخدم في قاعدة البيانات
    user = database.find_user(username)

    # التحقق من صحة البيانات
    if not user or not verify_password(password, user.password_hash):
        return {"error": "Invalid username or password"}

    # بيانات التوكن (Claims)
    payload = {
        "sub": user.id,                         # ID المستخدم
        "name": user.name,                      # اسم المستخدم
        "role": user.role,                      # صلاحية المستخدم
        "iat": datetime.utcnow(),               # وقت إنشاء التوكن
        "exp": datetime.utcnow() + timedelta(hours=1)  # انتهاء بعد ساعة
    }

    # إنشاء التوكن وتوقيعه
    token = jwt.encode(payload, SECRET_KEY, algorithm="HS256")

    return {
        "message": "Login successful",
        "token": token
    }


# ----------------------------------
# Protected Route: التحقق من التوكن
# ----------------------------------
def protected_route(request):

    # قراءة Authorization Header
    auth_header = request.headers.get("Authorization")

    # التحقق من وجود التوكن
    if not auth_header or not auth_header.startswith("Bearer "):
        return {"error": "Authorization token missing"}

    # استخراج التوكن
    token = auth_header.split(" ")[1]

    try:
        # فك التوكن والتحقق منه
        payload = jwt.decode(token, SECRET_KEY, algorithms=["HS256"])

        user_id = payload["sub"]
        user_name = payload["name"]
        user_role = payload["role"]

        return {
            "message": f"Welcome {user_name}",
            "user_id": user_id,
            "role": user_role
        }

    except jwt.ExpiredSignatureError:
        return {"error": "Token expired"}

    except jwt.InvalidTokenError:
        return {"error": "Invalid token"}
